import React from "react";

export default function Forecast({ city = "Atlanta, US", forecastData = [] }) {
  // Example placeholder forecast data if none is passed
  const sampleData = [
    { day: "Monday", icon: "🌤️", high: "30°C", low: "20°C" },
    { day: "Tuesday", icon: "🌧️", high: "28°C", low: "19°C" },
    { day: "Wednesday", icon: "⛅", high: "31°C", low: "21°C" },
    { day: "Thursday", icon: "🌩️", high: "27°C", low: "18°C" },
    { day: "Friday", icon: "☀️", high: "33°C", low: "22°C" },
  ];

  const data = forecastData.length ? forecastData : sampleData;

  return (
    <div className="w-full">
      {/* City name on desktop */}
      <div className="hidden sm:block mb-4">
        <h2 className="text-xl font-semibold text-white">
          {city} - 16-Day Forecast
        </h2>
      </div>

      <div className="space-y-3">
        {data.map((item, idx) => (
          <div
            key={idx}
            className="
              w-full flex items-center justify-between
              bg-black/60 backdrop-blur-md text-white rounded-xl px-4 py-3
              shadow-lg hover:ring-1 hover:ring-purple-500/40 transition
            "
          >
            {/* Left side: day + icon */}
            <div className="flex items-center space-x-4">
              <span className="text-lg font-medium">{item.day}</span>
              <span className="text-2xl">{item.icon}</span>
            </div>

            {/* Right side: temps */}
            <div className="flex items-center space-x-4">
              <span className="text-lg font-semibold">{item.high}</span>
              <span className="text-gray-300">{item.low}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
